replies.msg:
用香港阿里雲, 但係大陸仔寫, 著名o既拼音variable name終於出現 <img src="/assets/faces/dog/smile.gif" class="hkgmoji" /><br />
<br />
<pre><code data-type="">function check1() {
    var name = $('#xingming').val();
    var email = $(&quot;#email&quot;).val();
    var neirong = $(&quot;#neirong&quot;).val();
    var myreg2 = /^([a-zA-Z0-9]+[_|\_|\.]?)*[a-zA-Z0-9]+@([a-zA-Z0-9]+[-|_|\_|\.]?)*[a-zA-Z0-9]+\.[a-zA-Z]{2,3}$/;

    if(name==''){alert(&quot;姓名不能為空！&quot;); return false;}
    if(!myreg2.test(email)){
        alert('郵箱不能為空！');
        return false;
    }
    if(neirong==''){alert(&quot;內容不能為空！&quot;); return false;}

}</code></pre>

